mapper.update:
UPDATE LINE
SET remaining_data = remaining_data - #{amount}
WHERE line_id = #{lineId}
  AND remaining_data >= #{amount}

UPDATE FAMILY
SET pool_remaining_data = pool_remaining_data + #{amount},
    pool_total_data = pool_total_data + #{amount}
WHERE family_id = #{familyId}

mapper.select:
SELECT COUNT(*)
FROM FAMILY_LINE
WHERE family_id = #{familyId}
  AND line_id = #{lineId}

SELECT COUNT(*)
FROM FAMILY_LINE fl
JOIN LINE l ON fl.line_id = l.line_id
WHERE fl.family_id = #{familyId}
  AND l.user_id = #{userId}
  AND fl.role = 'OWNER'
